#include<iostream>#include<algorithm>#include<vector>using namespace std;int main(){    int n;    cin>>n;        int sereja=0;    int dima = 0;        int a;    vector<int> v;    for(int i=0 ; i<n ; i++){        cin>>a;        v.push_back(a);    }        int left = 0;    int right = n-1;    bool turn = true;  while(left <= right){    int pick;        if(v[left] > v[right]){        pick = v[left];        left++;    } else {        pick = v[right];        right--;    }     if(turn) sereja += pick;    else dima += pick;     turn = !turn; }        cout<<sereja<<" "<<dima;    return 0;}